import os
import sqlite3


class AccessControlSystem(object):
    def __init__(self, db_path):
        self._db = sqlite3.connect(db_path)

    def open_file(self, file_name):
        access_level = self.__check_access(file_name)

        if access_level == 'r':
            return os.open(file_name, os.O_RDONLY)


